import{_ as i,o as a,c as e,ai as r}from"./chunks/framework.DKRJm8HN.js";const c=JSON.parse('{"title":"星露谷物语初相识","description":"","frontmatter":{"title":"星露谷物语初相识","date":"2026-03-25T00:00:00.000Z"},"headers":[],"relativePath":"docs/E-StardewValley/StardewValley-Introductiong.md","filePath":"docs/E-StardewValley/StardewValley-Introductiong.md"}'),t={name:"docs/E-StardewValley/StardewValley-Introductiong.md"};function n(d,l,p,o,u,h){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="星露谷物语初相识" tabindex="-1">星露谷物语初相识 <a class="header-anchor" href="#星露谷物语初相识" aria-label="Permalink to “星露谷物语初相识”">​</a></h1><h2 id="一切都从-wallpaper-engine-开始" tabindex="-1">一切都从 Wallpaper Engine 开始 <a class="header-anchor" href="#一切都从-wallpaper-engine-开始" aria-label="Permalink to “一切都从 Wallpaper Engine 开始”">​</a></h2><h3 id="✈️再一次从上海回到静宁" tabindex="-1">✈️再一次从上海回到静宁 <a class="header-anchor" href="#✈️再一次从上海回到静宁" aria-label="Permalink to “✈️再一次从上海回到静宁”">​</a></h3><p>2022 年底，新冠疫情基本结束。 2023 年元旦前，我也从感染病毒🦠中恢复过来差不多一周时间，按照 22 年初的决定辞职。 这份工作是从 2020 年 9 月中旬开始，期间我从中学到了很多，了解和接触到之前尚未真正见识过的东西，也经历了现在看来不值一提的“艰辛”。 办理完手续后，收拾好东西，邮寄回家。 元旦当天中午，我就迫不及待的乘坐从上海虹桥国际机场飞往兰州中川机场的飞机✈️。 机票是我提前半个多月已经购买好的。</p><h3 id="🏠在家的日子" tabindex="-1">🏠在家的日子 <a class="header-anchor" href="#🏠在家的日子" aria-label="Permalink to “🏠在家的日子”">​</a></h3><p>回到家后，临近春节，也就没有再外出。 就这样我开始了自 2013 年从学校🏫进入社会以来第二长时间的一次宅家——因为现在这次已经持续快一年了。 期间有太多无所事事，因此，开始了在网上冲浪🏄🏻。 闲来无事，朋友介绍了 Wallpapet Engine 做桌面壁纸管理，我好奇其高度自定义和响应式的功能，就下载来使用。自然而然就拥有了 steam。 在研究 Wallpaer Engine 期间，回想起大学时在网吧通宵玩的各种单机游戏，就这样慢慢地接触到了 steam 上流行的畅销游戏。 这个时候，因为我的游戏意识很差，没有游戏体验感，很快就退出了。此时，我还没有接触到 Stardew Valley 呢。 过完春节，又到外出打工的时候了——这好像是我们的宿命，不管体验好坏总🉐️出去。</p><h2 id="在外的两年" tabindex="-1">在外的两年 <a class="header-anchor" href="#在外的两年" aria-label="Permalink to “在外的两年”">​</a></h2><h3 id="银川的求职" tabindex="-1">银川的求职 <a class="header-anchor" href="#银川的求职" aria-label="Permalink to “银川的求职”">​</a></h3><p>中环，做太阳能板材料的，因某种原因被拒。</p><h3 id="棋盘井的工作和生活" tabindex="-1">棋盘井的工作和生活 <a class="header-anchor" href="#棋盘井的工作和生活" aria-label="Permalink to “棋盘井的工作和生活”">​</a></h3><p>因熟人介绍，所以顺利入职，毫无波澜。 一入职就开始了三班两倒（例如：今日白班，明晚夜班，后天白班，这样循环往复）。 2023 年精力旺盛，这样的日子给了我一种就这么持续下去也还好的错觉——离上一次这样类似的日子过去了十年。 刚开始稀里糊涂，什么也不懂，就是一天天上下班。一两个月后，我慢慢找回来了上班的状态，也开始投入进去。 那时候我们工段还是大工段没有拆分，十多个人，每天闹哄哄感觉非常地快乐。 工作中彼此相处融洽，偶尔有点脸红脖子粗也很快过去。</p><ul><li><p>就这样，在化工厂的一段难忘的日子开始了。</p><ul><li>上班开会（刚开始可有可无，后面几次事故后严格了）</li><li>接班（一直都很顺利）</li><li>巡检</li><li>必须的打扫卫生（那里都有）</li><li>拧阀门、拆装法兰（刚开始不会，没少被说）</li><li>其他各种杂事</li></ul></li><li><p>期间有两次亲历的中压蒸汽管道爆炸💥。</p><ul><li>第一次当时我离得远，没有造成直观的精神冲击。</li><li>第二次离得近，我亲身感受到了爆炸前后的那种氛围，紧张、无措，还有无知——如果当时事态进一步扩大，此刻我也没有机会在说道。</li></ul></li><li><p>随着几次事故的发生，甲醇合成氨车间变成了醇氨厂，换了厂长，工段拆分，领导们几经变化。</p><ul><li>所有事情变得重要，以前有的需要做的更扎实，没有的也要做起来</li><li>2023 年的冬天就在这种忙忙乱乱中度过了 <ul><li>特别冷🥶，基本每天晚上都要消冻</li><li>白天各种排液防冻</li><li>晚上还要偷偷找地方去睡觉😴，因为太胆小，经常熬过来 <ul><li>那种接近天亮的困倦让人很疲惫</li><li>9 点下班后，回到宿舍（2023 年 7 月-2024 年 6 月在外租房住）又很亢奋</li><li>11 点-12 点入睡，下午 5 点能醒是最好的状态，后面不到 4 点就醒来了</li></ul></li></ul></li><li>国庆前后，公司岗位和工资调整，有同事离职 <ul><li>中控 2 人，现场加班长 3 人</li><li>变得很忙，真的</li></ul></li><li>忘了哪天夜班，因工作在对讲机中和班长（大哥）发生争执 <ul><li>第二天，李工在工段群中发通报 <ul><li>不服从管理</li><li>考核 100 元</li><li>如有下次，退回人事</li></ul></li><li>认罚，此后已服</li></ul></li><li>年底因人员不足，未回家过年 <ul><li>除夕那晚，我和斌哥下班回去后直接就睡</li><li>钱都还了账，只买了 2-3 斤羊肉🐏</li><li>自己炖得，自我感觉不错🙂</li><li>22 年底初建厂有 5000 年终奖💰，23 年只有</li></ul></li></ul></li><li><p>2024 年初，李工离职。</p><ul><li>4 月检修 <ul><li>我和斌哥继续倒班</li><li>监护，配合化验室的妹妹们做样</li><li>其他杂事</li></ul></li><li>5 月前后，大牙🦷离职</li><li>因公司所谓经营困难，市场环境不好 <ul><li>人员优化</li><li>工段仅仅 5 人，事情繁多</li></ul></li></ul></li><li><p>经历多次开停车。</p><ul><li>焦炉煤气加热炉和综合加热炉点火灭火 <ul><li>点火和灭火期间，各种动静，怕了</li></ul></li><li>纯氧转化炉投氧和切氧 <ul><li>更是怕了</li></ul></li><li>管道沙眼和法兰泄漏、着火</li></ul></li><li><p>怕了，真的。</p><ul><li>2024 年下半年，已经决定来年离职</li></ul></li><li><p>后面也就一日挨一日。</p><ul><li>期间在 6 月搬进宿舍，与宝宝同居，甚美</li><li>此刻，Stardew Valley 进入了我的视线，渐渐上头</li></ul></li><li><p>最终，在 2025 年 6 月 12 日结束了这份工作。</p></li></ul><h2 id="🏠在家的日子-1" tabindex="-1">🏠在家的日子 <a class="header-anchor" href="#🏠在家的日子-1" aria-label="Permalink to “🏠在家的日子”">​</a></h2><p>除了日常锁事，其余时间都在Stardew Valley、读书、练习五笔打字。</p>',14)])])}const _=i(t,[["render",n]]);export{c as __pageData,_ as default};
